const incoming = $input.first().json;
const headers = incoming.headers ?? {};
const body = incoming.body ?? incoming;
const optionalSecret = $env.PDF_IMPORT_WEBHOOK_SECRET;
const apiKey = headers['x-api-key'] ?? headers['X-Api-Key'] ?? headers['X-API-KEY'];

if (optionalSecret && apiKey !== optionalSecret) {
  throw new Error('Unauthorized: invalid x-api-key for PDF import workflow');
}

if (!body.batchId || !body.fileName || !body.fileContentBase64 || body.fileMimeType !== 'application/pdf') {
  throw new Error('Invalid payload for PDF import workflow');
}

const categoryHint = body.categoryHint || 'auto';

return [{
  json: {
    batchId: body.batchId,
    fileName: body.fileName,
    fileMimeType: body.fileMimeType,
    categoryHint
  },
  binary: {
    data: {
      data: body.fileContentBase64,
      mimeType: body.fileMimeType,
      fileName: body.fileName
    }
  }
}];

const extracted = $input.first().json;
const source = $('Validate And Decode PDF').first().json;

const rawText = extracted.text ?? extracted.data ?? extracted.content ?? JSON.stringify(extracted);
const cleanText = String(rawText)
  .replace(/\r/g, '\n')
  .replace(/[\t ]+/g, ' ')
  .replace(/\n{3,}/g, '\n\n')
  .trim();

if (!cleanText) {
  throw new Error('No text extracted from PDF');
}

const truncatedText = cleanText.length > 120000 ? cleanText.slice(0, 120000) : cleanText;

const prompt = [
  'Ekstrak semua soal CPNS dari teks PDF berikut.',
  'Keluarkan JSON valid saja tanpa markdown fence.',
  'Output wajib berupa object dengan key parsedQuestions.',
  'Setiap item parsedQuestions harus memiliki field:',
  JSON.stringify({
    questionText: 'string',
    options: [
      { label: 'A', text: 'string' },
      { label: 'B', text: 'string' },
      { label: 'C', text: 'string' },
      { label: 'D', text: 'string' },
      { label: 'E', text: 'string' }
    ],
    detectedAnswer: 'A',
    category: 'TWK',
    subCategory: 'Tata Negara',
    topicTag: 'Hak dan Kewajiban Warga Negara',
    difficulty: 'medium',
    confidenceScore: 86.5,
    rawAiOutput: {},
    status: 'pending_review'
  }, null, 2),
  'Gunakan status rejected jika satu soal tidak bisa dipulihkan dengan aman.',
  `categoryHint: ${source.categoryHint}`,
  '',
  'Teks PDF:',
  truncatedText,
].join('\n\n');

const model = $env.OPENAI_MODEL || 'gpt-4.1-mini';
const llmRequest = {
  model,
  temperature: 0.1,
  response_format: { type: 'json_object' },
  messages: [
    {
      role: 'system',
      content: 'Anda adalah mesin ekstraksi soal CPNS dari PDF dan harus menjawab dalam JSON valid.'
    },
    {
      role: 'user',
      content: prompt
    }
  ]
};

return [{
  json: {
    batchId: source.batchId,
    categoryHint: source.categoryHint,
    extractedTextLength: cleanText.length,
    llmRequest
  }
}];

const llmResponse = $input.first().json;
let raw = llmResponse.choices?.[0]?.message?.content ?? llmResponse.output_text ?? llmResponse.content ?? llmResponse;
if (Array.isArray(raw)) {
  raw = raw.map((item) => item?.text ?? '').join('\n');
}
if (typeof raw === 'object') {
  raw = JSON.stringify(raw);
}
if (typeof raw !== 'string') {
  throw new Error('LLM response does not contain string content');
}

const cleaned = raw
  .replace(/^```json\s*/i, '')
  .replace(/^```\s*/i, '')
  .replace(/```$/i, '')
  .trim();

let parsed;
try {
  parsed = JSON.parse(cleaned);
} catch {
  throw new Error('LLM returned invalid JSON for parsedQuestions');
}

const parsedQuestionsRaw = Array.isArray(parsed.parsedQuestions)
  ? parsed.parsedQuestions
  : Array.isArray(parsed.questions)
    ? parsed.questions
    : [];

const normalized = parsedQuestionsRaw.map((item) => {
  const options = Array.isArray(item.options) ? item.options : [];
  const normalizedOptions = ['A', 'B', 'C', 'D', 'E'].map((label, index) => ({
    label,
    text: String(options[index]?.text ?? options.find((option) => option?.label === label)?.text ?? '').trim(),
  }));

  const hasAllOptionTexts = normalizedOptions.every((option) => option.text.length > 0);
  const category = ['TWK', 'TIU', 'TKP'].includes(item.category) ? item.category : null;
  const difficulty = ['easy', 'medium', 'hard'].includes(item.difficulty) ? item.difficulty : null;
  const detectedAnswer = ['A', 'B', 'C', 'D', 'E'].includes(item.detectedAnswer) ? item.detectedAnswer : null;
  const status = item.status === 'rejected' || !item.questionText || !hasAllOptionTexts ? 'rejected' : 'pending_review';

  return {
    questionText: String(item.questionText ?? '').trim(),
    options: normalizedOptions,
    detectedAnswer,
    category,
    subCategory: item.subCategory ? String(item.subCategory).trim() : null,
    topicTag: item.topicTag ? String(item.topicTag).trim() : null,
    difficulty,
    confidenceScore: typeof item.confidenceScore === 'number' ? item.confidenceScore : null,
    rawAiOutput: item.rawAiOutput ?? item,
    status,
  };
});

const validCount = normalized.filter((item) => item.status === 'pending_review').length;
const invalidCount = normalized.filter((item) => item.status === 'rejected').length;

return [{
  json: {
    parsedQuestions: normalized,
    totalParsed: normalized.length,
    validCount,
    invalidCount
  }
}];
